using Microsoft.EntityFrameworkCore;

// EF9 breaking change: Cosmos DB discriminator property renamed from
// "Discriminator" to "$type", and values changed to short names.
// For existing documents that use "Discriminator", explicitly configure
// the old property name and values to avoid data mismatches.

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Session>().ToContainer("Sessions");

        // Preserve backward compatibility with existing documents
        modelBuilder.Entity<Session>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Session>("Session");
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string UserId { get; set; } = default!;
    public DateTime ExpiresAt { get; set; }
}

using Microsoft.EntityFrameworkCore;

// EF9 breaking change: The Cosmos DB provider no longer supports
// synchronous I/O. Calls like ToList(), First(), Single(), etc.
// throw InvalidOperationException. Use async equivalents instead.

class CosmosQueryService
{
    private readonly CosmosDbContext _db;

    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // BEFORE (EF8 — synchronous, now broken in EF9):
    //   var sessions = _db.Sessions.Where(s => s.UserId == userId).ToList();
    //   var session  = _db.Sessions.FirstOrDefault(s => s.Id == id);
    //   var count    = _db.Sessions.Count();

    // AFTER (EF9 — async equivalents):
    public async Task<List<Session>> GetUserSessionsAsync(string userId)
        => await _db.Sessions.Where(s => s.UserId == userId).ToListAsync();

    public async Task<Session?> FindSessionAsync(string id)
        => await _db.Sessions.FirstOrDefaultAsync(s => s.Id == id);

    public async Task<int> CountSessionsAsync()
        => await _db.Sessions.CountAsync();
}

